Variables are containers for storing data values. In JavaScript, you can declare variables using `var`, `let`, or `const`.

**Variable Declaration Keywords:**

**1. `let` (Modern, Recommended)**
```javascript
let name = 'John';
let age = 25;
age = 26; // Can be reassigned
```
- Block-scoped (only accessible within the block it's declared)
- Can be reassigned
- Cannot be redeclared in the same scope
- Use for variables that will change

**2. `const` (Modern, Recommended)**
```javascript
const PI = 3.14159;
const greeting = 'Hello';
// greeting = 'Hi'; // Error - cannot be reassigned
```
- Block-scoped
- Cannot be reassigned (immutable)
- Must be initialized when declared
- Use for values that won't change

**3. `var` (Old, Not Recommended)**
```javascript
var oldWay = 'This is the old way';
```
- Function-scoped (can leak outside blocks)
- Can be reassigned and redeclared
- Can cause bugs due to hoisting
- Avoid in modern JavaScript

**Variable Naming Rules:**
- Must start with a letter, underscore (_), or dollar sign ($)
- Can contain letters, numbers, underscores, and dollar signs
- Cannot start with a number
- Cannot be a reserved keyword (let, const, function, etc.)
- Case-sensitive (myVar and myvar are different)

**Best Practices:**
```javascript
// Good - descriptive names
let userName = 'John';
let userAge = 25;
let isLoggedIn = true;

// Bad - unclear names
let x = 'John';
let a = 25;
let b = true;

// Use camelCase for multi-word names
let firstName = 'John';
let lastName = 'Doe';
let totalScore = 100;
```

**Complete Example:**
```javascript
let userName = 'Alice';
let userAge = 30;
const MAX_SCORE = 100;
let currentScore = 85;

console.log(`Player: ${userName}`);
console.log(`Age: ${userAge}`);
console.log(`Score: ${currentScore}/${MAX_SCORE}`);
```

JavaScript has several built-in data types that determine what kind of data a variable can hold and what operations can be performed on it.

**JavaScript Data Types:**

**1. Primitive Types (Immutable):**

**String** - Text data
```javascript
let firstName = 'John';
let lastName = "Doe";
let message = `Hello, ${firstName}`; // Template literal
```

**Number** - Numeric data (integers and decimals)
```javascript
let age = 25;           // Integer
let price = 19.99;       // Decimal
let pi = 3.14159;       // More precise
let negative = -10;      // Negative number
```

**Boolean** - True or false values
```javascript
let isStudent = true;
let isLoggedIn = false;
let hasPermission = true;
```

**Undefined** - Variable declared but not assigned
```javascript
let x;
console.log(x); // undefined
```

**Null** - Intentional absence of value
```javascript
let emptyValue = null;
```

**Symbol** - Unique identifiers (ES6+)
```javascript
let sym = Symbol('description');
```

**BigInt** - Large integers (ES2020+)
```javascript
let bigNumber = 9007199254740991n;
```

**2. Reference Types (Mutable):**

**Array** - Ordered list of values
```javascript
let colors = ['red', 'green', 'blue'];
let numbers = [1, 2, 3, 4, 5];
let mixed = ['text', 123, true, null];
```

**Object** - Key-value pairs
```javascript
let person = {
  name: 'John',
  age: 30,
  isStudent: true
};
```

**Function** - Reusable code blocks
```javascript
let greet = function(name) {
  return `Hello, ${name}`;
};
```

**Type Checking:**
```javascript
let value = 'Hello';
console.log(typeof value); // 'string'

let num = 42;
console.log(typeof num); // 'number'

let arr = [1, 2, 3];
console.log(typeof arr); // 'object' (arrays are objects)
```

**Type Conversion:**
```javascript
// String to Number
let strNum = '123';
let num = Number(strNum); // 123
let num2 = parseInt(strNum); // 123
let num3 = parseFloat('3.14'); // 3.14

// Number to String
let num = 123;
let str = String(num); // '123'
let str2 = num.toString(); // '123'

// Boolean Conversion
let value = 'Hello';
let bool = Boolean(value); // true

// Falsy values (convert to false):
// 0, '', null, undefined, NaN, false

// Truthy values (convert to true):
// All other values, including empty arrays and objects
```

JavaScript operators are used to perform operations on variables and values. They are the symbols that tell JavaScript to perform specific actions.

**Arithmetic Operators:**
```javascript
let a = 10, b = 3;

// Addition
let sum = a + b;        // 13

// Subtraction
let diff = a - b;       // 7

// Multiplication
let product = a * b;    // 30

// Division
let quotient = a / b;   // 3.333...

// Modulus (remainder)
let remainder = a % b;  // 1

// Exponentiation
let power = a ** b;     // 1000

// Increment
let x = 5;
x++;                  // x = 6 (post-increment)
++x;                  // x = 7 (pre-increment)

// Decrement
let y = 5;
y--;                  // y = 4 (post-decrement)
--y;                  // y = 3 (pre-decrement)
```

**Assignment Operators:**
```javascript
let x = 10;

x = 20;           // Simple assignment
x += 5;           // x = x + 5  → 25
x -= 3;           // x = x - 3  → 22
x *= 2;           // x = x * 2  → 44
x /= 4;           // x = x / 4  → 11
x %= 3;           // x = x % 3  → 2
x **= 2;          // x = x ** 2 → 4
```

**Comparison Operators:**
```javascript
let a = 5, b = 10;

// Equal (value only)
a == b;           // false
'5' == 5;         // true (type coercion)

// Not equal (value only)
a != b;           // true
'5' != 5;         // false

// Strict equal (value and type)
a === b;          // false
'5' === 5;        // false

// Strict not equal
a !== b;          // true
'5' !== 5;        // true

// Greater than
a > b;            // false

// Less than
a < b;            // true

// Greater than or equal
a >= b;           // false

// Less than or equal
a <= b;           // true
```

**Logical Operators:**
```javascript
let a = true, b = false;

// AND (returns true if both are true)
a && b;           // false
true && true;     // true
true && false;    // false

// OR (returns true if at least one is true)
a || b;           // true
true || false;    // true
false || false;   // false

// NOT (reverses the boolean)
!a;               // false
!b;               // true
```

**String Operators:**
```javascript
// Concatenation
let firstName = 'John';
let lastName = 'Doe';
let fullName = firstName + ' ' + lastName; // 'John Doe'

// Template literals (modern)
let greeting = `Hello, ${firstName}!`; // 'Hello, John!'

// String comparison
let a = 'apple';
let b = 'banana';
a < b;            // true (alphabetical order)
```

**Ternary Operator (Conditional):**
```javascript
let age = 18;
let canVote = age >= 18 ? 'Yes' : 'No';
console.log(canVote); // 'Yes'

// Equivalent to if-else:
let canVote;
if (age >= 18) {
  canVote = 'Yes';
} else {
  canVote = 'No';
}
```

Functions are reusable blocks of code that perform a specific task. They are fundamental to JavaScript programming and help organize code, avoid repetition, and make programs more maintainable.

**Why Use Functions?**
- **Reusability**: Write code once, use it multiple times
- **Organization**: Break complex problems into smaller pieces
- **Maintainability**: Easier to debug and update
- **Readability**: Makes code more understandable

**Function Declaration:**
```javascript
function greet(name) {
  return `Hello, ${name}!`;
}

// Calling the function
console.log(greet('Alice')); // 'Hello, Alice!'
console.log(greet('Bob'));   // 'Hello, Bob!'
```

**Function Expression:**
```javascript
const greet = function(name) {
  return `Hello, ${name}!`;
};

console.log(greet('Charlie')); // 'Hello, Charlie!'
```

**Arrow Functions (ES6, Modern):**
```javascript
// Simple arrow function
const greet = (name) => {
  return `Hello, ${name}!`;
};

// Arrow function with implicit return
const greet = (name) => `Hello, ${name}!`;

// Arrow function with single parameter (parentheses optional)
const greet = name => `Hello, ${name}!`;

// Arrow function with no parameters
const sayHello = () => 'Hello!';
```

**Function Parameters:**
```javascript
// Multiple parameters
function add(a, b) {
  return a + b;
}

console.log(add(5, 3)); // 8

// Default parameters (ES6)
function greet(name = 'Guest') {
  return `Hello, ${name}!`;
}

console.log(greet());        // 'Hello, Guest!'
console.log(greet('Alice')); // 'Hello, Alice!'
```

**Return Values:**
```javascript
// Function with return value
function multiply(a, b) {
  return a * b;
}

let result = multiply(4, 5);
console.log(result); // 20

// Function without return (returns undefined)
function logMessage(message) {
  console.log(message);
}

let value = logMessage('Hello');
console.log(value); // undefined
```

**Function Scope:**
```javascript
let globalVar = 'I am global';

function myFunction() {
  let localVar = 'I am local';
  console.log(globalVar); // Accessible
  console.log(localVar);  // Accessible
}

myFunction();
console.log(globalVar); // Accessible
// console.log(localVar); // Error - not accessible outside function
```

**Complete Example:**
```javascript
// Calculate area of different shapes
function calculateRectangleArea(width, height) {
  return width * height;
}

function calculateCircleArea(radius) {
  return Math.PI * radius * radius;
}

function calculateTriangleArea(base, height) {
  return 0.5 * base * height;
}

// Using the functions
console.log('Rectangle:', calculateRectangleArea(5, 3));
console.log('Circle:', calculateCircleArea(4));
console.log('Triangle:', calculateTriangleArea(6, 4));
```
